      // First call: git status (has changes)
      // Second call: git add -A
      // Third call: git commit
      mockSpawnSync
        .mockReturnValueOnce({
          status: 0,
          stdout: Buffer.from("M src/file.ts\n"),
          stderr: Buffer.from(""),
