        })
        .mockReturnValueOnce({
          status: 0,
          stdout: Buffer.from(""),
          stderr: Buffer.from(""),
          pid: 1234,
          signal: null,
          output: [],
        });

      const result = createCheckpointCommit("/path/to/worktree", 123, false);

      expect(result).toBe(true);
      expect(mockSpawnSync).toHaveBeenCalledTimes(3);

      // Verify git add was called
